-- ─────────────────────────────────────────────────────────────────────────
-- Venezuela te busca — Contenido inicial para PRODUCCIÓN (Supabase)
--
-- Para qué sirve: cuando despliegas con Supabase, los datos de ejemplo de
-- `src/lib/seed.ts` NO se usan (esos son solo para el modo demostración local).
-- Este archivo carga en la base real un contenido inicial (hospitales reales de
-- la zona, puntos de ayuda y publicaciones de comunidad) para que el sitio no
-- salga vacío en el lanzamiento.
--
-- Cómo usarlo:
--   1. Ejecuta PRIMERO `supabase/schema.sql` (crea las tablas y columnas).
--   2. Luego pega y ejecuta ESTE archivo en el SQL Editor de Supabase.
--   3. Es re-ejecutable sin duplicar: usa IDs fijos con `on conflict do nothing`,
--      así que si lo corres otra vez solo carga las filas que falten.
--
-- ⚠️ TELÉFONOS: los números de hospitales son de fuentes públicas (jun. 2026) y
-- DEBES CONFIRMARLOS antes de promocionarlos. Donde no se halló un número
-- confiable se dejó NULL (Periférico de Pariata, Hospital Naval, Materno de
-- Macuto). Los puntos de ayuda no llevan teléfono: confírmalo con cada
-- organización y edítalo desde el sitio.
--
-- El estado de capacidad de los hospitales (operativo/saturado/lleno) y los
-- votos/reacciones son ILUSTRATIVOS del escenario; la comunidad los irá ajustando.
-- ─────────────────────────────────────────────────────────────────────────

begin;

-- ── Hospitales (reales) ─────────────────────────────────────────────────────
on conflict (id) do nothing;

-- ── Puntos de ayuda ─────────────────────────────────────────────────────────
-- contact_phone NULL a propósito: confírmalo con cada organización y edítalo en el sitio.
  -- Alojamiento: hogares que abren sus puertas
  ('c0000000-0000-4000-8000-000000000010', 'Casas que abren sus puertas — Maiquetía', ARRAY['alojamiento']::aid_point_type[], 'La Guaira', 'Maiquetía (varias familias anfitrionas)', 'Cupos según disponibilidad', 'Familias de Maiquetía ofrecen un techo a quienes se quedaron sin vivienda. Trato digno y seguro; prioridad a familias con niños y adultos mayores. Coordina antes de llegar.', 'Red de hogares solidarios', null, false, true, 8, 0, 19, now() - interval '40 minutes', now() - interval '40 minutes'),
  ('c0000000-0000-4000-8000-000000000011', 'Hogar de paso — Caracas (Los Palos Grandes)', ARRAY['alojamiento','comida']::aid_point_type[], 'Distrito Capital', 'Los Palos Grandes, Caracas', 'Noche; coordinar de día', 'Espacio para recibir a familias evacuadas de La Guaira por una o varias noches. Hay agua y comida. Escribe para coordinar el cupo.', 'Familia anfitriona', null, false, true, 6, 0, 13, now() - interval '77 minutes', now() - interval '77 minutes'),
  -- Acopio en el exterior (diáspora). verified=false: confirmar la fuente/organización.
  ('c0000000-0000-4000-8000-000000000012', 'Punto de acopio — Cartagena (Colombia)', ARRAY['comida','ropa','medicina']::aid_point_type[], null, 'Cartagena, Colombia', '9:00 a. m. – 5:00 p. m.', 'Venezolanos en Cartagena reúnen alimentos no perecederos, ropa e insumos para enviar a la zona afectada. Confirma con la organización antes de llevar tu aporte.', 'Colectivo de venezolanos en Cartagena', null, false, true, 9, 1, 28, now() - interval '114 minutes', now() - interval '114 minutes'),
  ('c0000000-0000-4000-8000-000000000013', 'Punto de acopio — Medellín (Colombia)', ARRAY['comida','ropa']::aid_point_type[], null, 'Medellín, Colombia', 'Tardes', 'Recolección de donaciones en Medellín para subir en caravana hacia la frontera. Reciben alimentos, ropa de abrigo y artículos de aseo.', 'Voluntarios en Medellín', null, false, true, 7, 0, 21, now() - interval '151 minutes', now() - interval '151 minutes'),
  ('c0000000-0000-4000-8000-000000000014', 'Punto de acopio — Bogotá (Colombia)', ARRAY['comida','medicina','ropa']::aid_point_type[], null, 'Bogotá, Colombia', 'Lun a Sáb', 'Centro de recolección en Bogotá. Priorizan medicinas, fórmula infantil y artículos de higiene. Verifica el punto exacto antes de ir.', 'Red solidaria Bogotá', null, false, true, 6, 0, 17, now() - interval '188 minutes', now() - interval '188 minutes'),
  ('c0000000-0000-4000-8000-000000000015', 'Punto de acopio — Panamá', ARRAY['comida','ropa']::aid_point_type[], null, 'Ciudad de Panamá, Panamá', 'Fines de semana', 'Comunidad venezolana en Panamá reúne donaciones y coordina envíos. Confirma logística antes de aportar.', 'Venezolanos en Panamá', null, false, true, 5, 0, 12, now() - interval '225 minutes', now() - interval '225 minutes'),
  ('c0000000-0000-4000-8000-000000000016', 'Punto de acopio — Cúcuta (frontera, Colombia)', ARRAY['comida','medicina','ropa']::aid_point_type[], null, 'Cúcuta, Colombia (paso fronterizo)', 'Lun a Dom', 'Punto cercano a la frontera para concentrar ayuda que cruza hacia Venezuela. Priorizan medicinas, alimentos y agua. Coordina el cruce con la organización.', 'Voluntarios en Cúcuta', null, false, true, 10, 1, 26, now() - interval '262 minutes', now() - interval '262 minutes'),
  ('c0000000-0000-4000-8000-000000000017', 'Punto de acopio — Madrid (España)', ARRAY['ropa','medicina']::aid_point_type[], null, 'Madrid, España', 'Tardes entre semana', 'La diáspora en Madrid reúne aportes y coordina envíos solidarios. Reciben medicinas, ropa de abrigo y donaciones económicas verificadas.', 'Venezolanos en Madrid', null, false, true, 6, 0, 18, now() - interval '299 minutes', now() - interval '299 minutes'),
  ('c0000000-0000-4000-8000-000000000018', 'Punto de acopio — Miami (EE. UU.)', ARRAY['medicina','ropa']::aid_point_type[], null, 'Miami, Florida, EE. UU.', 'Fines de semana', 'Comunidad venezolana en Miami recolecta insumos médicos y artículos de primera necesidad para enviar. Verifica el punto y la logística antes de aportar.', 'Venezolanos en Miami', null, false, true, 8, 0, 22, now() - interval '336 minutes', now() - interval '336 minutes'),
  ('c0000000-0000-4000-8000-000000000019', 'Punto de acopio — Santiago (Chile)', ARRAY['comida','ropa']::aid_point_type[], null, 'Santiago, Chile', 'Sábados', 'Colectivo venezolano en Santiago reúne donaciones y coordina envíos. Reciben alimentos no perecederos y abrigo.', 'Venezolanos en Chile', null, false, true, 5, 0, 14, now() - interval '373 minutes', now() - interval '373 minutes'),
  ('c0000000-0000-4000-8000-000000000020', 'Punto de acopio — Lima (Perú)', ARRAY['comida','medicina']::aid_point_type[], null, 'Lima, Perú', 'Lun a Sáb', 'Recolección en Lima para coordinar envíos solidarios. Priorizan medicinas y alimentos. Confirma con la organización.', 'Venezolanos en Perú', null, false, true, 5, 0, 11, now() - interval '410 minutes', now() - interval '410 minutes'),
  ('c0000000-0000-4000-8000-000000000021', 'Punto de acopio — Quito (Ecuador)', ARRAY['ropa','comida']::aid_point_type[], null, 'Quito, Ecuador', 'Fines de semana', 'Diáspora en Quito reúne ropa, abrigo y alimentos para envío. Verifica el punto de entrega antes de ir.', 'Venezolanos en Ecuador', null, false, true, 4, 0, 9, now() - interval '447 minutes', now() - interval '447 minutes'),
  ('c0000000-0000-4000-8000-000000000022', 'Punto de acopio — Boa Vista (frontera, Brasil)', ARRAY['comida','agua','medicina']::aid_point_type[], null, 'Boa Vista, Brasil (frontera sur)', 'Lun a Dom', 'Punto fronterizo en Brasil para canalizar ayuda hacia el sur de Venezuela. Reciben agua, alimentos y medicinas. Coordina el cruce.', 'Voluntarios en Boa Vista', null, false, true, 6, 0, 13, now() - interval '484 minutes', now() - interval '484 minutes')
on conflict (id) do nothing;

-- ── Comunidad / publicaciones ───────────────────────────────────────────────
on conflict (id) do nothing;

-- ── Comentarios en publicaciones (ambiente de conversación) ─────────────────
on conflict (id) do nothing;

-- ── Denuncias de irregularidades (ejemplos RESPONSABLES, sin señalar a nadie) ─
on conflict (id) do nothing;

-- ── Mascotas y voluntarios: SIN ejemplos ────────────────────────────────────
-- Antes había mascotas y voluntarios de muestra; se quitaron para no mostrar
-- registros genéricos como si fueran reales. Estas secciones se llenan solo con
-- lo que publique la gente.

-- ── Héroes (sección curada de Noticias) ─────────────────────────────────────
-- Reconocimientos POR CATEGORÍA (no señalan a personas concretas) para no
-- atribuir nada falso; por eso van sin fuente y verificados. La comunidad puede
-- proponer héroes con nombre y fuente: esos nacen verified=false hasta el visto
-- bueno del moderador.
on conflict (id) do nothing;

-- ── Noticias curadas (con su fuente real) ───────────────────────────────────
on conflict (id) do nothing;

commit;
